import { events, type Edition, type CtaEvent } from './events';
import { langOrder } from '../i18n/utils';
import type { Lang } from '../i18n/ui';

// Generated by scripts/extract_editions.py — committee + results per edition.
import sbrc2026 from './editions/sbrc-2026.json';
import sbrc2025 from './editions/sbrc-2025.json';
import wgrs2024 from './editions/wgrs-2024.json';
import sbseg2026 from './editions/sbseg-2026.json';
import sbseg2025 from './editions/sbseg-2025.json';
import sbseg2024 from './editions/sbseg-2024.json';
import wticg2023 from './editions/wticg-2023.json';

export interface CommitteeGroup {
  group: string;
  members: string[];
}
export interface ResultRow {
  seals: { D: boolean; F: boolean; S: boolean; R: boolean };
  title: string;
  track: string | null;
  link: string | null;
}
export interface EditionData {
  slug: string;
  legacyDir: string;
  committee: CommitteeGroup[];
  results: ResultRow[];
}

const dataBySlug: Record<string, EditionData> = {
  'sbrc-2026': sbrc2026 as EditionData,
  'sbrc-2025': sbrc2025 as EditionData,
  'wgrs-2024': wgrs2024 as EditionData,
  'sbseg-2026': sbseg2026 as EditionData,
  'sbseg-2025': sbseg2025 as EditionData,
  'sbseg-2024': sbseg2024 as EditionData,
  'wticg-2023': wticg2023 as EditionData,
};

export interface Contact {
  email: string;
  name?: string;
}

// The committee's shared inbox; used as the default per-edition contact and on
// the CTA-level contact page.
export const COMMITTEE_EMAIL = 'comite.tecnico.de.artefatos@gmail.com';

// Per-edition contact overrides; defaults to the committee's shared inbox.
const DEFAULT_CONTACT: Contact = { email: COMMITTEE_EMAIL };
const contactBySlug: Record<string, Contact> = {
  'wgrs-2024': { name: 'Tiago Heinrich (UFPR)', email: 'theinrich@inf.ufpr.br' },
};

export interface ResolvedEdition {
  edition: Edition;
  event: CtaEvent;
  data: EditionData;
  contact: Contact;
  /** Which year's shared instructions apply to this edition. */
  instructionsYear: number;
}

/** Flat list of every edition with its parent event, sorted newest first. */
export function allEditions(): { event: CtaEvent; edition: Edition }[] {
  const out: { event: CtaEvent; edition: Edition }[] = [];
  for (const event of events) {
    for (const edition of event.editions) out.push({ event, edition });
  }
  return out.sort((a, b) => b.edition.year - a.edition.year);
}

export function resolveEdition(slug: string): ResolvedEdition | undefined {
  for (const event of events) {
    const edition = event.editions.find((e) => e.slug === slug);
    if (edition) {
      return {
        edition,
        event,
        data: dataBySlug[slug] ?? { slug, legacyDir: '', committee: [], results: [] },
        contact: contactBySlug[slug] ?? DEFAULT_CONTACT,
        instructionsYear: edition.year,
      };
    }
  }
  return undefined;
}

/** Localized "EVENT YEAR" heading, e.g. "SBSeg 2026". */
export function editionTitle(r: ResolvedEdition): string {
  return `${r.event.code} ${r.edition.year}`;
}

/** getStaticPaths helper: every (lang, edition) pair with the resolved edition. */
export function editionStaticPaths() {
  const paths = [];
  for (const lang of langOrder) {
    for (const { edition } of allEditions()) {
      paths.push({
        params: { lang, edition: edition.slug },
        props: { r: resolveEdition(edition.slug)! },
      });
    }
  }
  return paths;
}

export type { Edition, CtaEvent, Lang };
